mapper.select:
SELECT p.id, p.position_name, p.position_code, p.dept_id, p.sort_order, p.status, p.create_time, p.update_time FROM sys_position p LEFT JOIN sys_dept d ON p.dept_id = d.id
AND p.position_name LIKE CONCAT('%', #{positionName}, '%')
AND p.position_code LIKE CONCAT('%', #{positionCode}, '%')
AND p.status = #{status}
AND p.dept_id = #{deptId}
ORDER BY p.sort_order ASC, p.create_time DESC

